#include <stdio.h>
#include <setjmp.h>
#include <signal.h>
#include <stdlib.h>

sigjmp_buf jump_buffer;
volatile sig_atomic_t jump_required = 0;

void signal_handler(int signum) {
 jump_required = 1;
 siglongjmp(jump_buffer, 1); // Jump back with value 1
}

int main() {
 struct sigaction sa;
 sa.sa_handler = signal_handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;
 sigaction(SIGSEGV, &sa, NULL);

 int ret = sigsetjmp(jump_buffer, 1); // Save signal mask

 if (ret == 0) {
 printf("Initial setup - continuing execution\n");
 // Simulate some work
 // Raise signal to test recovery
 raise(SIGSEGV);
 } else {
 printf("Recovered from signal! Return value: %d\n", ret);
 }

 return 0;
}

