#include <setjmp.h>
#include <signal.h>
#include <stdio.h>

sigjmp_buf buf_no_mask; // For savemask=0
sigjmp_buf buf_mask; // For savemask=1

void handler_no_mask(int sig) {
 siglongjmp(buf_no_mask, 1);
}

void handler_with_mask(int sig) {
 siglongjmp(buf_mask, 1);
}

int main() {
 // Install signal handlers (code omitted for brevity)

 // savemask = 0: signal mask NOT saved
 if (sigsetjmp(buf_no_mask, 0) == 0) {
 printf("First call with savemask=0\n");
 raise(SIGINT);
 } else {
 printf("Returned via siglongjmp, savemask was NOT saved\n");
 }

 // savemask = 1: signal mask IS saved
 if (sigsetjmp(buf_mask, 1) == 0) {
 printf("First call with savemask=1\n");
 raise(SIGINT);
 } else {
 printf("Returned via siglongjmp, savemask WAS restored\n");
 }

 return 0;
}

#include <setjmp.h>
#include <stdio.h>

sigjmp_buf jump_buffer;

// WITHOUT volatile - may have issues
int counter; // Problematic

// WITH volatile - safe
volatile int safe_counter;

void trigger_jump(void) {
 siglongjmp(jump_buffer, 1);
}

int main(void) {
 if (sigsetjmp(jump_buffer, 0) == 0) {
 counter = 10;
 safe_counter = 10;
 trigger_jump();
 } else {
 // After longjmp, 'counter' may have
 // indeterminate value due to optimization
 // 'safe_counter' will reliably be 10
 printf("counter = %d (may be wrong!)\n", counter);
 printf("safe_counter = %d (correct)\n", safe_counter);
 }
 return 0;
}
